export const getCompleteAppointmentUrl = (id: number,) => {




  return `/api/appointments/${id}/complete`
}

/**
 * @summary Mark appointment as completed
 */
export const completeAppointment = async (id: number,
    completeInput?: CompleteInput, options?: RequestInit): Promise<Appointment> => {

  return customFetch<Appointment>(getCompleteAppointmentUrl(id),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      completeInput,)
  }
);}




